def judge_pair(a, b, judge):
    s1 = judge(a, b)        # candidate A first
    s2 = judge(b, a)        # candidate B first
    if s1.winner == s2.winner:
        return s1.winner
    return "tie"            # disagree -> tie, never break arbitrarily
